    if len(bitstring) != 2 * REGISTER_WIDTH:
        continue
    reg1 = bitstring[:REGISTER_WIDTH]
    reg2 = bitstring[REGISTER_WIDTH:]
    expected_reg2 = ''
    for i, b in enumerate(reg1):
        if i == 0 or i == 2:
            expected_reg2 += '1' if b == '0' else '0'
        else:
